def gen(rng, size):
    budget = max(1, min(size, 25)) // 2
    def build(pairs):
        if pairs <= 0:
            return ''
        # split between wrapping one pair and placing siblings
        if pairs == 1:
            return '()'
        if rng.random() < 0.5:
            return '(' + build(pairs - 1) + ')'
        left = rng.randint(1, pairs - 1)
        return build(left) + build(pairs - left)
    s = build(budget)
    if not s:
        s = '()'
    return [s]

