class Solution:
    def scoreOfParentheses(self, s):
        # Brute: recursively split the string into top-level balanced chunks,
        # scoring each chunk independently then summing.
        def score(t):
            if t == '()':
                return 1
            depth = 0
            total = 0
            start = 0
            for i, ch in enumerate(t):
                depth += 1 if ch == '(' else -1
                if depth == 0:
                    chunk = t[start:i + 1]
                    if chunk == '()':
                        total += 1
                    else:
                        total += 2 * score(chunk[1:-1])
                    start = i + 1
            return total
        return score(s)

