class Solution:
    def scoreOfParentheses(self, s):
        total = 0
        depth = 0
        for i, ch in enumerate(s):
            if ch == '(':
                depth += 1
            else:
                depth -= 1
                if s[i - 1] == '(':
                    total += 1 << depth
        return total

